sql:
SELECT MAX(attempt_time) AS latest_attempt_time
  FROM auth_attempts
  WHERE user_id = 1;

SELECT ip_address
FROM auth_attempts
WHERE success = 1;

SELECT attempt_time, success
FROM auth_attempts
ORDER BY attempt_time DESC;

SELECT MAX((julianday(sm.last_activity_time) - julianday(sm.start_time)) * 24 * 60) AS max_session_duration
FROM session_management sm
WHERE sm.session_status = 'active';

SELECT COUNT(*) AS failed_attempts
FROM auth_attempts
WHERE user_id = 1 AND success = 0;

external_knowledge:
- 'since April 1st, 2023' refers to any date on or after '2023-04-01 00:00:00'; 
- 'names' refers to usernames chosen by the users; 
- 'IDs' refers to unique identifiers for each user; 
- 'failed login attempts' are authentication attempts with a 'success' status of 0; 
- 'the number of notifications they've received' refers to the count of notifications with matching attempt_ids in the failed_authentication_notifications table.
